qry:select.qry:xquery:
	for $r in sql('
	SELECT
		ADE.oi_adelanto,
		ADE.f_adelanto,
		ADE.o_descripcion,
		ADE.n_monto_adel,
		ADE.n_monto_a_rendir,
		ADE.n_criticidad,
		ADE.d_destino,
		ADE.d_orden_cheque,
		ADE.o_adelanto,
		CAR.oi_carpeta,
		CAR.c_carpeta,
		CAR.d_carpeta,
		SUJ.c_sujeto,
		SUJ.d_sujeto,
		UBI.d_ubicacion,
		EMP.c_empresa,
		EMP.d_empresa,
		TIP.c_tipo_adelanto,
		TIP.d_tipo_adelanto,
		EA.c_estado_ant,
		EA.d_estado_ant,
		ADE.f_necesidad_fondos
	FROM
		LEG04_ADELANTOS as ADE,
		LEG01_CARPETAS as CAR,
		LEG40_CLASIF_SUJ as CLA,
		LEG40_SUJETOS as SUJ,
		ORG03_UBICACIONES as UBI,
		ORG03_EMPRESAS as EMP,
		LEG56_TIPO_ADEL as TIP,
		LEG54_ESTADOS_ANT as EA
	JOIN
		ADE.oi_carpeta INNER CAR.oi_carpeta,
		ADE.oi_clasif_sujeto INNER CLA.oi_clasif_sujeto,
		CLA.oi_sujeto INNER SUJ.oi_sujeto,
		ADE.oi_ubicacion LEFT OUTER UBI.oi_ubicacion,
		CAR.oi_empresa LEFT OUTER EMP.oi_empresa,
		ADE.oi_tipo_adelanto LEFT OUTER TIP.oi_tipo_adelanto,
		EA.oi_estado_ant INNER ADE.oi_estado_ant

	WHERE
	  CAR.oi_estado_carpeta != 11 
	  AND
	  ADE.oi_carpeta IN ({%=$PARAM/@oi_carpeta%})

		{%? (#FILTRO:@oi_empresa!='')                  
			{% AND EMP.oi_empresa = {#FILTRO:@oi_empresa} %} 
			{% %} 
		%}

		{%? (#FILTRO:@oi_carpeta!='')                  
			{% AND CAR.oi_carpeta = {#FILTRO:@oi_carpeta} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_clasif_sujeto!='')                  
			{% AND ADE.oi_clasif_sujeto = {#FILTRO:@oi_clasif_sujeto} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_ubicacion!='')                  
			{% AND ADE.oi_ubicacion = {#FILTRO:@oi_ubicacion} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_tipo_adelanto!='')                  
			{% AND ADE.oi_tipo_adelanto = {#FILTRO:@oi_tipo_adelanto} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_estado_ant!='')                  
			{% AND ADE.oi_estado_ant = {#FILTRO:@oi_estado_ant} %} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='1' and #FILTRO:@l_rendido='0' and #FILTRO:@l_rendido_parcial='0')                  
			{% AND EA.d_estado_ant = \'Activo\'%} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='0' and #FILTRO:@l_rendido='1' and #FILTRO:@l_rendido_parcial='0')                  
			{% AND EA.d_estado_ant = \'Rendido\'%} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='0' and #FILTRO:@l_rendido='0' and #FILTRO:@l_rendido_parcial='1')                  
		{%AND EA.d_estado_ant = \'Rendido parcialmente\'%} 
			{% %} 
		%} 
			{%? (#FILTRO:@l_activo='1' and #FILTRO:@l_rendido='1' and #FILTRO:@l_rendido_parcial='0')                  
		{%AND (EA.d_estado_ant = \'Activo\' OR EA.d_estado_ant = \'Rendido\') %} 
			{% %} 
		%}
			{%? (#FILTRO:@l_activo='1' and #FILTRO:@l_rendido='0' and #FILTRO:@l_rendido_parcial='1')                  
		{%AND (EA.d_estado_ant = \'Activo\' OR EA.d_estado_ant = \'Rendido parcialmente\') %} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='0' and #FILTRO:@l_rendido='1' and #FILTRO:@l_rendido_parcial='1')                  
		{%AND (EA.d_estado_ant = \'Rendido\' OR EA.d_estado_ant = \'Rendido parcialmente\') %} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='1' and #FILTRO:@l_rendido='1' and #FILTRO:@l_rendido_parcial='0')                  
		{%AND (EA.d_estado_ant = \'Activo\' OR EA.d_estado_ant = \'Rendido\') %} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='1' and #FILTRO:@l_rendido='0' and #FILTRO:@l_rendido_parcial='1')                  
		{%AND (EA.d_estado_ant = \'Activo\' OR EA.d_estado_ant = \'Rendido parcialmente\') %} 
			{% %} 
		%}
		{%? (#FILTRO:@l_activo='0' and #FILTRO:@l_rendido='1' and #FILTRO:@l_rendido_parcial='1')                  
		{%AND (EA.d_estado_ant = \'Rendido\' OR EA.d_estado_ant = \'Rendido parcialmente\') %} 
			{% %} 
		%}


	{%?(#FILTRO:@f_adelanto_d!='') {% AND ADE.f_adelanto >= {#FILTRO:@f_adelanto_d} %} {% %} %}
	{%?(#FILTRO:@f_adelanto_h!='') {% AND ADE.f_adelanto <  {Datetime(Number(Datetime(#FILTRO:@f_adelanto_h))+1)} %} {% %} %}


	ORDER BY oi_adelanto ASC
')/ROWS/ROW
